module top_module(input [15:0] vec, output reg [4:0] count);integer i;
    integer zero_count;
    always @(vec) begin
        zero_count = 0;
        for (i=15; i>=0; i=i-1) begin
            if(vec[i] == 1'b1) begin
                zero_count = zero_count + 1;
            end
        end
        count = zero_count;
    end
endmodule
